class Transport{constructor({transportDataCallback:t,gameName:a,playerID:s,matchID:n,credentials:e,numPlayers:c}){this.connectionStatusCallback=()=>{},this.isConnected=!1,this.transportDataCallback=t,this.gameName=a||"default",this.playerID=s||null,this.matchID=n||"default",this.credentials=e,this.numPlayers=c||2}subscribeToConnectionStatus(t){this.connectionStatusCallback=t}setConnectionStatus(t){this.isConnected=t,this.connectionStatusCallback()}notifyClient(t){this.transportDataCallback(t)}}export{Transport as T};